#!/usr/bin/env node
// Fetches real contribution calendar data from GitHub GraphQL API
// and generates an SVG matching the ACE dark neon aesthetic.

const QUERY = `
query ($login: String!) {
  user(login: $login) {
    contributionsCollection {
      contributionCalendar {
        totalContributions
        weeks {
          contributionDays {
            contributionCount
            date
            weekday
          }
        }
      }
    }
  }
}`;

async function fetchContributions(username, token) {
  const res = await fetch('https://api.github.com/graphql', {
    method: 'POST',
    headers: {
      Authorization: `bearer ${token}`,
      'Content-Type': 'application/json',
      'User-Agent': 'ace-readme',
    },
    body: JSON.stringify({ query: QUERY, variables: { login: username } }),
  });

  if (!res.ok) throw new Error(`GitHub API ${res.status}: ${await res.text()}`);
  const json = await res.json();
  if (json.errors) throw new Error(json.errors.map(e => e.message).join(', '));
  return json.data.user.contributionsCollection.contributionCalendar;
}

function generateSVG(calendar) {
  const weeks = calendar.weeks;
  const total = calendar.totalContributions;

  const cellSize = 13;
  const gap = 2;
  const step = cellSize + gap;
  const padLeft = 28;
  const padTop = 52;
  const padRight = 28;
  const padBottom = 40;
  const gridW = weeks.length * step;
  const gridH = 7 * step;
  const width = gridW + padLeft + padRight;
  const height = gridH + padTop + padBottom;

  // ACE color levels (dark → neon cyan)
  const colors = [
    'rgba(30,30,50,0.6)',
    'rgba(45,74,110,0.8)',
    'rgba(74,126,200,0.85)',
    'rgba(126,231,255,0.9)',
    'rgba(184,240,255,0.95)',
  ];

  function getLevel(count) {
    if (count === 0) return 0;
    if (count <= 2) return 1;
    if (count <= 5) return 2;
    if (count <= 9) return 3;
    return 4;
  }

  let cells = '';
  for (let w = 0; w < weeks.length; w++) {
    const days = weeks[w].contributionDays;
    for (let d = 0; d < days.length; d++) {
      const level = getLevel(days[d].contributionCount);
      const x = padLeft + w * step;
      const y = padTop + d * step;
      const color = colors[level];
      const stroke = level > 2
        ? color.replace(/[\d.]+\)$/, `${0.3 + level * 0.1})`)
        : 'rgba(60,60,100,0.15)';
      const sw = level > 2 ? 1 : 0.5;
      cells += `<rect x="${x}" y="${y}" width="${cellSize}" height="${cellSize}" rx="2" fill="${color}" stroke="${stroke}" stroke-width="${sw}" />\n`;
    }
  }

  // Month labels
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  let monthLabels = '';
  let lastMonth = -1;
  for (let w = 0; w < weeks.length; w++) {
    const firstDay = weeks[w].contributionDays[0];
    if (!firstDay) continue;
    const month = new Date(firstDay.date).getMonth();
    if (month !== lastMonth) {
      lastMonth = month;
      const x = padLeft + w * step;
      monthLabels += `<text x="${x}" y="${padTop - 8}" fill="#4a4a6a" font-size="9" font-family="Inter, sans-serif">${months[month]}</text>\n`;
    }
  }

  // Day labels
  const dayLabels = ['','Mon','','Wed','','Fri',''];
  let dayLabelsSvg = '';
  for (let d = 0; d < 7; d++) {
    if (dayLabels[d]) {
      const y = padTop + d * step + cellSize - 2;
      dayLabelsSvg += `<text x="${padLeft - 6}" y="${y}" fill="#4a4a6a" font-size="8" font-family="Inter, sans-serif" text-anchor="end">${dayLabels[d]}</text>\n`;
    }
  }

  // Legend
  const legendX = padLeft + gridW - 120;
  const legendY = padTop + gridH + 14;
  let legend = `<text x="${legendX}" y="${legendY + 9}" fill="#4a4a6a" font-size="9" font-family="Inter, sans-serif">Less</text>`;
  for (let i = 0; i < 5; i++) {
    legend += `<rect x="${legendX + 28 + i * 14}" y="${legendY}" width="10" height="10" rx="2" fill="${colors[i]}" />`;
  }
  legend += `<text x="${legendX + 100}" y="${legendY + 9}" fill="#4a4a6a" font-size="9" font-family="Inter, sans-serif">More</text>`;

  return `<!-- Generated by ace-readme contribution fetcher -->
<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
  <defs>
    <radialGradient id="cbg1" cx="50%" cy="50%" r="50%">
      <stop offset="0%" stop-color="rgba(80,50,220,0.3)" />
      <stop offset="100%" stop-color="rgba(80,50,220,0)" />
    </radialGradient>
    <linearGradient id="c-scan" x1="0%" y1="0%" x2="100%" y2="0%">
      <stop offset="0%" stop-color="rgba(120,200,255,0)" />
      <stop offset="40%" stop-color="rgba(120,200,255,0.08)" />
      <stop offset="50%" stop-color="rgba(160,120,255,0.25)" />
      <stop offset="60%" stop-color="rgba(120,200,255,0.08)" />
      <stop offset="100%" stop-color="rgba(120,200,255,0)" />
    </linearGradient>
  </defs>
  <style>
    @keyframes c-drift { 0%, 100% { transform: translate(0, 0); opacity: 0.5; } 50% { transform: translate(30px, -15px); opacity: 0.85; } }
    @keyframes c-scan { 0% { transform: translate(-${width}px, 0); } 100% { transform: translate(${width}px, 0); } }
    #c-bg1 { animation: c-drift 10s ease-in-out infinite; }
    #c-scan1 { animation: c-scan 5s linear infinite; }
  </style>
  <rect width="${width}" height="${height}" rx="20" fill="#06060a" stroke="rgba(110,80,220,0.2)" stroke-width="1" />
  <ellipse id="c-bg1" cx="${width/2}" cy="${height/2}" rx="${width*0.4}" ry="${height*0.5}" fill="url(#cbg1)" />
  <rect id="c-scan1" x="0" y="${height/2}" width="160" height="1" fill="url(#c-scan)" />
  <text x="${padLeft}" y="24" fill="rgba(120,200,255,0.8)" font-size="10" font-family="Inter, sans-serif" letter-spacing="3" font-weight="700">CONTRIBUTION MATRIX</text>
  <text x="${padLeft}" y="38" fill="#4a4a6a" font-size="11" font-family="Inter, sans-serif">${total} contributions in the last year</text>
  ${monthLabels}
  ${dayLabelsSvg}
  ${cells}
  ${legend}
</svg>`;
}

// ── Main ──
const username = process.env.GITHUB_USER || 'acedmicabhishek';
const token = process.env.GITHUB_TOKEN;

if (!token) {
  console.error('No GITHUB_TOKEN set — skipping contribution calendar generation.');
  process.exit(0);
}

(async () => {
  try {
    console.log(`Fetching contributions for @${username}...`);
    const calendar = await fetchContributions(username, token);
    console.log(`  ${calendar.totalContributions} contributions in ${calendar.weeks.length} weeks`);
    const svg = generateSVG(calendar);

    const fs = await import('node:fs');
    const path = await import('node:path');
    const outDir = path.resolve(process.cwd(), '.github/assets');
    fs.mkdirSync(outDir, { recursive: true });
    const outPath = path.join(outDir, 'contribution-calendar.svg');
    fs.writeFileSync(outPath, svg, 'utf-8');
    console.log(`  Saved to ${outPath}`);
  } catch (err) {
    console.error(`Error: ${err.message}`);
    process.exit(1);
  }
})();
